#!/bin/bash
# MESH TELEMETRY BRIDGE
# Connects live edge telemetry (X-headers) to the Aeon Monitor.

CYAN="\x1b[38;5;51m"
AMBER="\x1b[38;5;214m"
RESET="\x1b[0m"
BOLD="\x1b[1m"

echo -e "${CYAN}${BOLD}━┫ MESH TELEMETRY BRIDGE ACTIVE ┣━${RESET}"

# Usage: ./scripts/mesh_telemetry_bridge.sh <BASE64_ASSESSMENT>
# Or: pipe a response header into it.

B64_JSON=$1

if [ -z "$B64_JSON" ]; then
    echo -e "${AMBER}Waiting for telemetry on stdin...${RESET}"
    read -r B64_JSON
fi

if [ -z "$B64_JSON" ]; then
    echo -e "${AMBER}ERROR: No telemetry data provided.${RESET}"
    exit 1
fi

# Convert to PleromaticFrame
cargo run --release --bin telemetry-frame -- --json "$B64_JSON" --output fingerprint.frame
